public interface IObserver {
  void Update(int value);
}

public class Subject {
  private readonly List<IObserver> _observers = new List<IObserver>();
  public int Value { get; private set; }

  public void Subscribe(IObserver observer) => _observers.Add(observer);
  public void SetValue(int value) {
    Value = value;
    foreach (var observer in _observers) observer.Update(value);
  }
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void Subject_NotifiesAllObservers_OnStateChange() {
  var subject = new Subject();
  var a = new TestObserver();
  var b = new TestObserver();
  subject.Subscribe(a);
  subject.Subscribe(b);

  subject.SetValue(42);

  Assert.AreEqual(42, a.LastValue);
  Assert.AreEqual(42, b.LastValue);
}

private class TestObserver : IObserver {
  public int LastValue { get; private set; }
  public void Update(int value) { LastValue = value; }
}
